            <t.icon className={`w-5 h-5 ${adjustTab === t.id ? 'text-indigo-400' : ''}`} />
            <span className="text-[8px] font-black uppercase tracking-widest">{t.label}</span>
          </button>
        ))}
      </div>

      <div 
        ref={canvasRef}
        className="relative h-48 cursor-crosshair overflow-hidden group"
        onClick={handlePointClick}
      >
        {adjustTab === 'color' && (
          <div className="w-full h-full bg-gradient-to-r from-red-500 via-yellow-500 via-green-500 via-cyan-500 via-blue-500 via-purple-500 to-red-500 opacity-80" />
