const ARView: React.FC<{ state: ProductState; onBack: () => void }> = ({ state, onBack }) => {
  const videoRef = React.useRef<HTMLVideoElement>(null);
  const [cameraStatus, setCameraStatus] = useState<'requesting' | 'active' | 'denied' | 'not-found'>('requesting');
  const [calibrationStep, setCalibrationStep] = useState(0);

  useEffect(() => {
    let stream: MediaStream | null = null;
    async function startCamera() {
      if (!navigator.mediaDevices?.getUserMedia) {
        setCameraStatus('not-found');
        return;
      }
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
          setCameraStatus('active');
          setTimeout(() => setCalibrationStep(1), 1500);
          setTimeout(() => setCalibrationStep(2), 3500);
        }
      } catch (err: any) {
        setCameraStatus(err.name === 'NotAllowedError' ? 'denied' : 'not-found');
      }
    }
    startCamera();
    return () => stream?.getTracks().forEach(track => track.stop());
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-black overflow-hidden flex flex-col">
      <div className="absolute inset-0 z-0">
        {cameraStatus === 'active' ? (
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover opacity-60" />
        ) : (
          <div className="w-full h-full bg-zinc-900 flex items-center justify-center p-12 text-center">
            <div className="max-w-xs space-y-4">
              {cameraStatus === 'requesting' ? <Loader2 className="w-10 h-10 text-indigo-500 animate-spin mx-auto" /> : <AlertCircle className="w-12 h-12 text-red-500 mx-auto" />}
              <p className="text-[10px] font-black uppercase tracking-widest text-white/50 italic">
                {cameraStatus === 'requesting' ? 'Syncing Optical Feed...' : 'Spatial Link Offline'}
              </p>
            </div>
          </div>
        )}
      </div>

      <div className="relative z-10 flex-1 flex items-center justify-center p-10 pointer-events-none">
        <div className={`w-full h-full max-w-lg aspect-[3/4] transition-all duration-1000 ${calibrationStep === 0 ? 'opacity-0 scale-90 blur-2xl' : 'opacity-100 scale-100 blur-0'}`}>
           <ThreeViewer state={state} />
        </div>
      </div>

      <div className="relative z-20 p-8 flex justify-between items-center bg-gradient-to-t from-black via-black/80 to-transparent">
        <button onClick={onBack} className="px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-3">
          <ChevronLeft className="w-4 h-4" /> EXIT STUDIO
        </button>
        <button className="p-6 bg-white rounded-full shadow-2xl hover:scale-110 active:scale-90 transition-all">
          <Camera className="w-6 h-6 text-black" />
        </button>
        <div className="w-[120px]" /> 
      </div>
    </div>
  );
};

