// Fix: Correctly augment the global JSX namespace to include Three.js elements for React Three Fiber.
// By listing specific elements as properties of IntrinsicElements instead of extending a type alias,
// we ensure successful merging with standard React HTML elements like div and span.
declare global {
  namespace JSX {
    interface IntrinsicElements {
      mesh: any;
      group: any;
      meshStandardMaterial: any;
      meshPhysicalMaterial: any;
      capsuleGeometry: any;
      cylinderGeometry: any;
      torusGeometry: any;
      sphereGeometry: any;
      ambientLight: any;
      spotLight: any;
      color: any;
    }
  }
}

