import React, { useRef, Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, ContactShadows, Environment, Float, Decal, useTexture } from '@react-three/drei';
import * as THREE from 'three';
import { ProductState } from '../types';

declare global {
  namespace React {
    namespace JSX {
      interface IntrinsicElements {
        mesh: any;
        group: any;
        meshStandardMaterial: any;
        meshPhysicalMaterial: any;
        capsuleGeometry: any;
        cylinderGeometry: any;
        torusGeometry: any;
        sphereGeometry: any;
        ambientLight: any;
        spotLight: any;
        color: any;
      }
    }
  }
}

interface ShirtProps {
  state: ProductState;
}

interface LogoDecalProps {
  url: string;
  position: [number, number, number];
  rotation: [number, number, number];
  scale: number;
}

const LogoDecal: React.FC<LogoDecalProps> = ({ url, position, rotation, scale }) => {
  const texture = useTexture(url);
  return (
    <Decal
      position={position}
      rotation={rotation}
      scale={scale}
    >
      <meshStandardMaterial
        map={texture}
        transparent
        polygonOffset
        polygonOffsetFactor={-1}
        roughness={1}
      />
    </Decal>
  );
};

const ShirtModel: React.FC<ShirtProps> = ({ state }) => {
  const meshRef = useRef<THREE.Mesh>(null);

  return (
    <group>
      <mesh ref={meshRef} castShadow receiveShadow position={[0, -0.05, 0]}>
        <cylinderGeometry args={[0.52, 0.52, 1.1, 64]} />
        <meshPhysicalMaterial 
          color={state.color} 
          roughness={0.95} 
          metalness={0}
          clearcoat={0}
          sheen={0.4}
          sheenRoughness={0.8}
          sheenColor={new THREE.Color('#ffffff')}
          envMapIntensity={0.4}
        />

        {state.logos.front && (
          <LogoDecal
            url={state.logos.front}
            position={[0, 0.2, 0.53]}
            rotation={[0, 0, 0]}
            scale={state.logoScale}
          />
        )}

        {state.logos.back && (
          <LogoDecal
            url={state.logos.back}
            position={[0, 0.2, -0.53]}
            rotation={[0, Math.PI, 0]}
            scale={state.logoScale}
          />
        )}
      </mesh>

      <group position={[0, 0.4, 0]}>
        <mesh position={[0.65, -0.1, 0]} rotation={[0, 0, -0.45]}>
          <cylinderGeometry args={[0.22, 0.24, state.type === 'long_sleeve' ? 1.0 : 0.48, 32]} />
          <meshPhysicalMaterial color={state.color} roughness={0.95} metalness={0} sheen={0.4} />
          {state.logos.leftSleeve && (
            <LogoDecal
              url={state.logos.leftSleeve}
              position={[0.24, 0, 0]}
              rotation={[0, Math.PI / 2, 0]}
              scale={state.logoScale * 0.4}
            />
          )}
        </mesh>

        <mesh position={[-0.65, -0.1, 0]} rotation={[0, 0, 0.45]}>
          <cylinderGeometry args={[0.22, 0.24, state.type === 'long_sleeve' ? 1.0 : 0.48, 32]} />
          <meshPhysicalMaterial color={state.color} roughness={0.95} metalness={0} sheen={0.4} />
          {state.logos.rightSleeve && (
            <LogoDecal
              url={state.logos.rightSleeve}
              position={[-0.24, 0, 0]}
              rotation={[0, -Math.PI / 2, 0]}
              scale={state.logoScale * 0.4}
            />
          )}
        </mesh>
      </group>

      <group position={[0, 0.55, 0]}>
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <torusGeometry args={[0.18, 0.05, 16, 64]} />
          <meshPhysicalMaterial color={state.color} roughness={0.95} metalness={0} />
        </mesh>
      </group>

      {state.type === 'polo' && (
        <group position={[0, 0.52, 0.12]}>
          <mesh rotation={[0.4, 0, 0]}>
            <torusGeometry args={[0.22, 0.06, 12, 40, Math.PI * 1.5]} />
            <meshPhysicalMaterial color={state.color} roughness={0.95} />
          </mesh>
        </group>
      )}

      {state.type === 'hoodie' && (
        <mesh position={[0, 0.6, -0.15]} rotation={[-0.4, 0, 0]}>
          <sphereGeometry args={[0.42, 32, 32, 0, Math.PI * 2, 0, Math.PI * 0.8]} />
          <meshPhysicalMaterial color={state.color} roughness={0.95} />
        </mesh>
      )}
    </group>
  );
};

const ThreeViewer: React.FC<ShirtProps> = ({ state }) => {
  return (
    <div className="w-full h-full overflow-hidden relative">
      <Canvas 
        shadows 
        camera={{ position: [0, 0, 3], fov: 24 }}
        gl={{ preserveDrawingBuffer: true, antialias: true, alpha: true }}
      >
        <ambientLight intensity={1.5} />
        <spotLight position={[5, 8, 5]} angle={0.2} penumbra={1} intensity={12} castShadow />
        <Suspense fallback={null}>
          <Float speed={1.2} rotationIntensity={0.02} floatIntensity={0.05}>
            <ShirtModel state={state} />
          </Float>
          <Environment preset="studio" />
          <ContactShadows position={[0, -1, 0]} opacity={0.5} scale={10} blur={2.8} far={3} />
        </Suspense>
        <OrbitControls 
          enablePan={false} 
          minDistance={1.8} 
          maxDistance={4.5} 
          makeDefault 
        />
      </Canvas>
    </div>
  );
};

export default ThreeViewer;

