import React, { useRef, Suspense, useEffect } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, ContactShadows, Environment, Float, Decal, useTexture, useGLTF } from '@react-three/drei';
import * as THREE from 'three';
import { ProductState } from '../types';

// Using a high-quality community asset for a realistic T-Shirt
const SHIRT_MODEL_URL = 'https://vazxmixjsiawhamofees.supabase.co/storage/v1/object/public/models/t-shirt/model.gltf';

interface ShirtProps {
  state: ProductState;
}

interface LogoDecalProps {
  url: string;
  position: [number, number, number];
  rotation: [number, number, number];
  scale: number;
}

const LogoDecal: React.FC<LogoDecalProps> = ({ url, position, rotation, scale }) => {
  const texture = useTexture(url);
  texture.colorSpace = THREE.SRGBColorSpace;

  return (
    <Decal
      position={position}
      rotation={rotation}
      scale={scale}
    >
      <meshStandardMaterial
        map={texture}
        transparent
        polygonOffset
        polygonOffsetFactor={-10}
        roughness={1}
        metalness={0}
        alphaTest={0.01}
      />
    </Decal>
  );
};

const ShirtModel: React.FC<ShirtProps> = ({ state }) => {
  // Load the GLTF model
  const { nodes, materials } = useGLTF(SHIRT_MODEL_URL) as any;
  const meshRef = useRef<THREE.Mesh>(null);

  // Sync state color and properties to the GLTF material
  useEffect(() => {
    if (materials.lambert1) {
      materials.lambert1.color.set(state.color);
      materials.lambert1.roughness = state.roughness;
      materials.lambert1.metalness = state.metalness;
      // For fabric, lambert or standard with high roughness is best
      materials.lambert1.needsUpdate = true;
    }
  }, [state.color, state.roughness, state.metalness, materials]);

  return (
    <group dispose={null}>
      <mesh
        ref={meshRef}
        castShadow
        receiveShadow
        geometry={nodes.T_Shirt_male.geometry}
        material={materials.lambert1}
        rotation={[Math.PI / 2, 0, 0]}
        scale={1.2} 
        position={[0, -0.6, 0]}
      >
        {/* Front Decal Placement */}
        {state.logos.front && (
          <LogoDecal
            url={state.logos.front}
            position={[0, 0.45, 0.15]}
            rotation={[0, 0, 0]}
            scale={state.logoScale * 0.45}
          />
        )}

        {/* Back Decal Placement */}
        {state.logos.back && (
          <LogoDecal
            url={state.logos.back}
            position={[0, 0.45, -0.15]}
            rotation={[0, Math.PI, 0]}
            scale={state.logoScale * 0.45}
          />
        )}

        {/* Left Sleeve Decal Placement */}
        {state.logos.leftSleeve && (
          <LogoDecal
            url={state.logos.leftSleeve}
            position={[0.18, 0.35, 0.05]}
            rotation={[0, Math.PI / 2, 0]}
            scale={state.logoScale * 0.25}
          />
        )}

        {/* Right Sleeve Decal Placement */}
        {state.logos.rightSleeve && (
          <LogoDecal
            url={state.logos.rightSleeve}
            position={[-0.18, 0.35, 0.05]}
            rotation={[0, -Math.PI / 2, 0]}
            scale={state.logoScale * 0.25}
          />
        )}
      </mesh>
    </group>
  );
};

const ThreeViewer: React.FC<ShirtProps> = ({ state }) => {
  return (
    <div className="w-full h-full overflow-hidden relative">
      <Canvas 
        shadows 
        camera={{ position: [0, 0, 2.5], fov: 32 }}
        gl={{ preserveDrawingBuffer: true, antialias: true, alpha: true }}
      >
        <ambientLight intensity={1.5} />
        <spotLight position={[10, 15, 10]} angle={0.25} penumbra={1} intensity={25} castShadow />
        <pointLight position={[-10, 10, -10]} intensity={10} />

        <Suspense fallback={null}>
          <Float speed={1.2} rotationIntensity={0.05} floatIntensity={0.1}>
            <ShirtModel state={state} />
          </Float>
          <Environment preset="studio" />
          <ContactShadows position={[0, -1, 0]} opacity={0.4} scale={10} blur={2.5} far={2} />
