// --- Global Handlers ---
window.navigate = (view) => {
  state.view = view;
  document.querySelectorAll('.view-section').forEach(v => v.classList.remove('active'));
  document.getElementById(`${view}-view`).classList.add('active');
  document.querySelectorAll('.nav-link').forEach(l => {
    l.classList.toggle('text-indigo-400', l.dataset.view === view);
    l.classList.toggle('text-white/40', l.dataset.view !== view);
  });
  if (view === 'studio' && !engine) {
    engine = new ThreeEngine('canvas-container');
    engine.createShirt(state.product);
  }
  if (view === 'catalog') renderCatalog();
  if (view === 'archive') renderArchive();
};

window.setTab = (tab) => {
  state.tab = tab;
  document.querySelectorAll('.tab-btn').forEach(b => {
    b.classList.toggle('bg-indigo-600', b.id === `tab-${tab}`);
    b.classList.toggle('text-white/30', b.id !== `tab-${tab}`);
  });
  const content = document.getElementById('tab-content');
  if (tab === 'basics') content.innerHTML = renderTabBasics();
  if (tab === 'design') content.innerHTML = renderTabDesign();
  if (tab === 'presets') content.innerHTML = `<div class="p-10 text-center opacity-30 uppercase text-[10px] font-black">AI Recommendations Loading...</div>`;
  renderIcons();
};

window.updateProductType = (type) => {
  state.product.type = type;
  engine.createShirt(state.product);
  window.setTab('basics');
};

window.handleLogoUpload = (e, pos) => {
  const file = e.target.files[0];
  if (file) {
    const reader = new FileReader();
    reader.onload = (ev) => {
      state.product.logos[pos] = ev.target.result;
      engine.createShirt(state.product);
      window.setTab('design');
    };
    reader.readAsDataURL(file);
  }
};

window.toggleAR = async (active) => {
  state.isAR = active;
  const overlay = document.getElementById('ar-overlay');
  const video = document.getElementById('ar-video');
  const arHost = document.getElementById('ar-canvas-host');

  if (active) {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      video.srcObject = stream;
      overlay.classList.remove('hidden');
      overlay.classList.add('flex');
      // Move Three.js renderer
      arHost.appendChild(engine.renderer.domElement);
      engine.onResize();
    } catch (err) { alert("Camera access denied."); state.isAR = false; }
  } else {
    overlay.classList.add('hidden');
    video.srcObject?.getTracks().forEach(t => t.stop());
    document.getElementById('canvas-container').appendChild(engine.renderer.domElement);
    engine.onResize();
  }
};

window.saveToArchive = () => {
  const btn = document.getElementById('archive-btn');
  btn.innerText = 'ARCHIVING...';
  setTimeout(() => {
    state.archive.push({ ...state.product, logos: { ...state.product.logos } });
    localStorage.setItem('archive', JSON.stringify(state.archive));
    btn.innerText = 'SAVED';
    btn.classList.add('bg-green-600');
    updateCartCount();
    setTimeout(() => {
      btn.innerText = 'COMMIT TO ARCHIVE';
      btn.classList.remove('bg-green-600');
    }, 2000);
  }, 1000);
};

window.loadFromCatalog = (color, type) => {
  const hsl = hexToHSL(color);
  state.product = { ...state.product, color, type, ...hsl };
  window.navigate('studio');
