    { id: 'ar-download-icon', icon: 'Download' }
  ];
  mapping.forEach(m => {
    const el = document.getElementById(m.id);
    if (el) {
      el.innerHTML = '';
      const icon = icons[m.icon];
      const svg = document.createElementNS("http://www.w3.org/2000/svg", "svg");
