// --- Utility Functions ---
const hslToHex = (h: number, s: number, l: number) => {
  l /= 100;
  const a = s * Math.min(l, 1 - l) / 100;
  const f = (n: number) => {
    const k = (n + h / 30) % 12;
    const color = l - a * Math.max(Math.min(k - 3, 9 - k, 1), -1);
    return Math.round(255 * color).toString(16).padStart(2, '0');
  };
  return `#${f(0)}${f(8)}${f(4)}`;
};

const hexToHSL = (hex: string) => {
  let r = parseInt(hex.slice(1, 3), 16) / 255;
  let g = parseInt(hex.slice(3, 5), 16) / 255;
  let b = parseInt(hex.slice(5, 7), 16) / 255;
  const max = Math.max(r, g, b), min = Math.min(r, g, b);
  let h = 0, s = 0, l = (max + min) / 2;
  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = (g - b) / d + (g < b ? 6 : 0); break;
      case g: h = (b - r) / d + 2; break;
      case b: h = (r - g) / d + 4; break;
    }
    h /= 6;
  }
  return { h: Math.round(h * 360), s: Math.round(s * 100), l: Math.round(l * 100) };
};

// --- Three.js Engine ---
class ThreeEngine {
  // Fix: Explicitly declare properties to resolve "Property does not exist on type 'ThreeEngine'" errors
  container: HTMLElement;
  scene: THREE.Scene;
  camera: THREE.PerspectiveCamera;
  renderer: THREE.WebGLRenderer;
  controls: OrbitControls;
  shirtGroup: THREE.Group;

  constructor(containerId: string) {
    const el = document.getElementById(containerId);
    if (!el) throw new Error("Container not found");
    this.container = el;
    this.scene = new THREE.Scene();
    this.camera = new THREE.PerspectiveCamera(35, this.container.clientWidth / this.container.clientHeight, 0.1, 1000);
    this.camera.position.z = 2.5;

    this.renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true, preserveDrawingBuffer: true });
    this.renderer.setSize(this.container.clientWidth, this.container.clientHeight);
    this.renderer.shadowMap.enabled = true;
    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.container.appendChild(this.renderer.domElement);

    this.controls = new OrbitControls(this.camera, this.renderer.domElement);
    this.controls.enablePan = false;
    this.controls.minDistance = 1.2;
    this.controls.maxDistance = 4;

    this.initLights();
    this.shirtGroup = new THREE.Group();
    this.scene.add(this.shirtGroup);
    this.animate();

    window.addEventListener('resize', () => this.onResize());
  }

  initLights() {
    const ambient = new THREE.AmbientLight(0xffffff, 1.2);
    this.scene.add(ambient);
    const spot = new THREE.SpotLight(0xffffff, 15);
    spot.position.set(10, 15, 10);
    spot.castShadow = true;
    this.scene.add(spot);
  }

  createShirt(product: Product) {
    this.shirtGroup.clear();
    const fabricMaterial = new THREE.MeshPhysicalMaterial({
      color: new THREE.Color(product.color),
      roughness: 0.95,
      metalness: 0,
      sheen: 0.2,
      sheenRoughness: 0.8,
      sheenColor: new THREE.Color(0xffffff),
      side: THREE.DoubleSide
    });

    const isLongSleeve = product.type === 'long_sleeve';
    const isHoodie = product.type === 'hoodie';
    const isPolo = product.type === 'polo';

    // Body
    const body = new THREE.Mesh(new THREE.CylinderGeometry(0.48, 0.52, 1, 64), fabricMaterial);
    body.castShadow = true;
    body.receiveShadow = true;
    this.shirtGroup.add(body);

    // Decals (Front/Back)
    if (product.logos.front) this.addDecal(body, product.logos.front, [0, 0.15, 0.51], [0, 0, 0], product.logoScale * 0.5);
    if (product.logos.back) this.addDecal(body, product.logos.back, [0, 0.15, -0.51], [0, Math.PI, 0], product.logoScale * 0.5);

    // Sleeves
    const sleeveLeft = new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.18, isLongSleeve ? 1.1 : 0.45, 32), fabricMaterial);
    sleeveLeft.position.set(0.62, 0.2, 0);
    sleeveLeft.rotation.z = -0.5;
    this.shirtGroup.add(sleeveLeft);
    if (product.logos.leftSleeve) this.addDecal(sleeveLeft, product.logos.leftSleeve, [0.21, 0, 0], [0, Math.PI / 2, 0], product.logoScale * 0.25);

    const sleeveRight = new THREE.Mesh(new THREE.CylinderGeometry(0.2, 0.18, isLongSleeve ? 1.1 : 0.45, 32), fabricMaterial);
    sleeveRight.position.set(-0.62, 0.2, 0);
    sleeveRight.rotation.z = 0.5;
    this.shirtGroup.add(sleeveRight);
    if (product.logos.rightSleeve) this.addDecal(sleeveRight, product.logos.rightSleeve, [-0.21, 0, 0], [0, -Math.PI / 2, 0], product.logoScale * 0.25);

    // Additive geometries (Polo/Hoodie)
    if (isPolo) {
      const collar = new THREE.Mesh(new THREE.TorusGeometry(0.22, 0.06, 12, 40, Math.PI * 1.4), fabricMaterial);
      collar.position.set(0, 0.48, 0.1);
      collar.rotation.x = 0.3;
      this.shirtGroup.add(collar);
    }
    if (isHoodie) {
      const hood = new THREE.Mesh(new THREE.SphereGeometry(0.42, 32, 32, 0, Math.PI * 2, 0, Math.PI * 0.7), fabricMaterial);
      hood.position.set(0, 0.6, -0.1);
      hood.rotation.x = -0.3;
      this.shirtGroup.add(hood);
    }

    this.shirtGroup.position.y = -0.2;
  }

  addDecal(mesh: THREE.Mesh, url: string, pos: [number, number, number], rot: [number, number, number], scale: number) {
    const loader = new THREE.TextureLoader();
    loader.load(url, (tex) => {
      tex.colorSpace = THREE.SRGBColorSpace;
      const mat = new THREE.MeshPhysicalMaterial({
        map: tex,
        transparent: true,
        polygonOffset: true,
        polygonOffsetFactor: -10,
        roughness: 1,
        metalness: 0,
        alphaTest: 0.01
      });
      const plane = new THREE.Mesh(new THREE.PlaneGeometry(scale, scale), mat);
      plane.position.set(...pos);
      plane.rotation.set(...rot);
      mesh.add(plane);
    });
  }

  onResize() {
    this.camera.aspect = this.container.clientWidth / this.container.clientHeight;
    this.camera.updateProjectionMatrix();
    this.renderer.setSize(this.container.clientWidth, this.container.clientHeight);
  }

  animate() {
    requestAnimationFrame(() => this.animate());
    this.shirtGroup.rotation.y += 0.005;
    this.renderer.render(this.scene, this.camera);
  }
}

