const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

async function getDesignSuggestions(theme: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Suggest 3 modern streetwear design concepts for a clothing brand. Theme: ${theme}. Return JSON.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              palette: { type: Type.ARRAY, items: { type: Type.STRING } },
              description: { type: Type.STRING }
            },
            required: ["title", "palette", "description"]
          }
        }
      }
    });
    // Fix: Access .text property instead of method
    return JSON.parse(response.text.trim());
  } catch (err) { console.error(err); return []; }
}

async function editLogoWithAI(base64Image: string, prompt: string) {
  try {
    const matches = base64Image.match(/^data:([^;]+);base64,(.+)$/);
    if (!matches) return null;
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ inlineData: { data: matches[2], mimeType: matches[1] } }, { text: prompt }] },
    });
    // Fix: Correctly extract image from inlineData part
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return part ? `data:${part.inlineData.mimeType};base64,${part.inlineData.data}` : null;
  } catch (err) { console.error(err); return null; }
}

