// Fix: Use (window as any) to assign global handlers and resolve "Property does not exist on type 'Window'" errors
(window as any).navigate = (view: string) => {
  state.view = view;
  document.querySelectorAll('.view-section').forEach(v => v.classList.remove('active'));
  const targetView = document.getElementById(`${view}-view`);
  if (targetView) targetView.classList.add('active');

  document.querySelectorAll('.nav-link').forEach(el => {
    // Fix: Cast element to HTMLElement to access dataset
    const l = el as HTMLElement;
    l.classList.toggle('text-indigo-400', l.dataset.view === view);
    l.classList.toggle('text-white/40', l.dataset.view !== view);
  });

  if (view === 'studio' && !engine) {
    engine = new ThreeEngine('canvas-container');
    engine.createShirt(state.product);
  }
  if (view === 'catalog') renderCatalog();
  if (view === 'archive') renderArchive();
};

(window as any).setTab = (tab: string) => {
  state.tab = tab;
  document.querySelectorAll('.tab-btn').forEach(b => {
    b.classList.toggle('bg-indigo-600', b.id === `tab-${tab}`);
    b.classList.toggle('text-white/30', b.id !== `tab-${tab}`);
  });
  const content = document.getElementById('tab-content');
  if (!content) return;
  if (tab === 'basics') content.innerHTML = renderTabBasics();
  if (tab === 'design') content.innerHTML = renderTabDesign();
  if (tab === 'presets') content.innerHTML = `<div class="p-10 text-center opacity-30 uppercase text-[10px] font-black">AI Recommendations Loading...</div>`;
  renderIcons();
};

(window as any).updateProductType = (type: string) => {
  state.product.type = type;
  if (engine) engine.createShirt(state.product);
  (window as any).setTab('basics');
};

(window as any).handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>, pos: keyof Product['logos']) => {
  const file = e.target.files?.[0];
  if (file) {
    const reader = new FileReader();
    reader.onload = (ev) => {
      state.product.logos[pos] = ev.target?.result as string;
      if (engine) engine.createShirt(state.product);
      (window as any).setTab('design');
    };
    reader.readAsDataURL(file);
  }
};

(window as any).toggleAR = async (active: boolean) => {
  state.isAR = active;
  const overlay = document.getElementById('ar-overlay');
  const video = document.getElementById('ar-video') as HTMLVideoElement;
  const arHost = document.getElementById('ar-canvas-host');

  if (active && overlay && video && arHost) {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      // Fix: Cast to HTMLVideoElement to assign srcObject
      video.srcObject = stream;
      overlay.classList.remove('hidden');
      overlay.classList.add('flex');
      // Move Three.js renderer
      if (engine) {
        arHost.appendChild(engine.renderer.domElement);
        engine.onResize();
      }
    } catch (err) { alert("Camera access denied."); state.isAR = false; }
  } else if (overlay && video) {
    overlay.classList.add('hidden');
    const stream = video.srcObject as MediaStream;
    stream?.getTracks().forEach(t => t.stop());
    video.srcObject = null;
    const canvasContainer = document.getElementById('canvas-container');
    if (engine && canvasContainer) {
      canvasContainer.appendChild(engine.renderer.domElement);
      engine.onResize();
    }
  }
};

(window as any).saveToArchive = () => {
  const btn = document.getElementById('archive-btn');
  if (!btn) return;
  btn.innerText = 'ARCHIVING...';
  setTimeout(() => {
    state.archive.push({ ...state.product, logos: { ...state.product.logos } });
    localStorage.setItem('archive', JSON.stringify(state.archive));
    btn.innerText = 'SAVED';
    btn.classList.add('bg-green-600');
    updateCartCount();
    setTimeout(() => {
      btn.innerText = 'COMMIT TO ARCHIVE';
      btn.classList.remove('bg-green-600');
    }, 2000);
  }, 1000);
};

(window as any).loadFromCatalog = (color: string, type: string) => {
  const hsl = hexToHSL(color);
  state.product = { ...state.product, color, type, ...hsl };
  (window as any).navigate('studio');
};

function updateCartCount() {
  const count = document.getElementById('cart-count');
  if (!count) return;
  count.innerText = state.archive.length.toString();
  count.classList.toggle('hidden', state.archive.length === 0);
}

