  return `#${f(0)}${f(8)}${f(4)}`;
};

const hexToHSL = (hex: string) => {
  let r = parseInt(hex.slice(1, 3), 16) / 255;
  let g = parseInt(hex.slice(3, 5), 16) / 255;
  let b = parseInt(hex.slice(5, 7), 16) / 255;
  const max = Math.max(r, g, b), min = Math.min(r, g, b);
  let h = 0, s = 0, l = (max + min) / 2;
  if (max !== min) {
    const d = max - min;
    s = l > 0.5 ? d / (2 - max - min) : d / (max + min);
    switch (max) {
      case r: h = (g - b) / d + (g < b ? 6 : 0); break;
      case g: h = (b - r) / d + 2; break;
      case b: h = (r - g) / d + 4; break;
    }
    h /= 6;
  }
  return { h: Math.round(h * 360), s: Math.round(s * 100), l: Math.round(l * 100) };
};

// --- 3D Components ---
const LogoDecal: React.FC<{ url: string; position: [number, number, number]; rotation: [number, number, number]; scale: number }> = ({ url, position, rotation, scale }) => {
  const texture = useTexture(url);
  texture.colorSpace = THREE.SRGBColorSpace;
  return (
    <Decal position={position} rotation={rotation} scale={scale}>
      <meshPhysicalMaterial map={texture} transparent polygonOffset polygonOffsetFactor={-10} roughness={1} metalness={0} alphaTest={0.01} />
    </Decal>
  );
};

const ShirtModel: React.FC<{ state: ProductState }> = ({ state }) => {
  const fabricMaterial = useMemo(() => new THREE.MeshPhysicalMaterial({
    color: new THREE.Color(state.color),
    roughness: 0.95,
    metalness: 0,
    sheen: 0.2,
    sheenRoughness: 0.8,
    sheenColor: new THREE.Color(0xffffff),
    side: THREE.DoubleSide
  }), [state.color]);

  const isLongSleeve = state.type === 'long_sleeve';
  const isHoodie = state.type === 'hoodie';
  const isPolo = state.type === 'polo';

  return (
    <group position={[0, -0.2, 0]}>
      <mesh castShadow receiveShadow>
        <cylinderGeometry args={[0.48, 0.52, 1, 64]} />
        <primitive object={fabricMaterial} attach="material" />
        {state.logos.front && <LogoDecal url={state.logos.front} position={[0, 0.15, 0.51]} rotation={[0, 0, 0]} scale={state.logoScale * 0.5} />}
        {state.logos.back && <LogoDecal url={state.logos.back} position={[0, 0.15, -0.51]} rotation={[0, Math.PI, 0]} scale={state.logoScale * 0.5} />}
      </mesh>
      <group position={[0, 0.35, 0]}>
        <mesh position={[0.62, -0.15, 0]} rotation={[0, 0, -0.5]}>
          <cylinderGeometry args={[0.2, 0.18, isLongSleeve ? 1.1 : 0.45, 32]} />
          <primitive object={fabricMaterial} attach="material" />
          {state.logos.leftSleeve && <LogoDecal url={state.logos.leftSleeve} position={[0.21, 0, 0]} rotation={[0, Math.PI / 2, 0]} scale={state.logoScale * 0.25} />}
        </mesh>
        <mesh position={[-0.62, -0.15, 0]} rotation={[0, 0, 0.5]}>
          <cylinderGeometry args={[0.2, 0.18, isLongSleeve ? 1.1 : 0.45, 32]} />
          <primitive object={fabricMaterial} attach="material" />
          {state.logos.rightSleeve && <LogoDecal url={state.logos.rightSleeve} position={[-0.21, 0, 0]} rotation={[0, -Math.PI / 2, 0]} scale={state.logoScale * 0.25} />}
        </mesh>
      </group>
      <mesh position={[0, 0.5, 0]} rotation={[Math.PI / 2, 0, 0]}>
        <torusGeometry args={[0.18, 0.05, 16, 64]} />
        <primitive object={fabricMaterial} attach="material" />
      </mesh>
      {isPolo && (
        <mesh position={[0, 0.48, 0.1]} rotation={[0.3, 0, 0]}>
          <torusGeometry args={[0.22, 0.06, 12, 40, Math.PI * 1.4]} />
          <primitive object={fabricMaterial} attach="material" />
        </mesh>
      )}
      {isHoodie && (
        <mesh position={[0, 0.6, -0.1]} rotation={[-0.3, 0, 0]}>
          <sphereGeometry args={[0.42, 32, 32, 0, Math.PI * 2, 0, Math.PI * 0.7]} />
          <primitive object={fabricMaterial} attach="material" />
        </mesh>
      )}
    </group>
  );
};

